import anthropic

# EU-region client configuration
# Sends inference traffic to EU AWS region
# Verify exact endpoint URL with Anthropic account team for your contract

eu_client = anthropic.Anthropic(
    base_url="https://api.eu.anthropic.com",  # EU endpoint — confirm with Anthropic
)

# Tag EU-origin requests for your own logging and TIA validation
def create_eu_message(messages: list, system: str = "") -> anthropic.types.Message:
    kwargs = {
        "model": "claude-sonnet-5",
        "max_tokens": 2048,
        "messages": messages,
    }
    if system:
        kwargs["system"] = system
    return eu_client.messages.create(**kwargs)
